import React, { useState, useMemo, useCallback } from 'react';
import { Button, DateRangeFilter, addToast } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { LedgerEntryDto } from '../../../services/kt/models';
import { createAccountSearchConfig } from '../../../components/search';
import { SearchInput } from '@linm-soft/common-components';
import { formatDateLocal, formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const SoCaiPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [accountCode, setAccountCode] = useState('111');
  const [accountName, setAccountName] = useState('');
  const [fromDate, setFromDate] = useState<string | undefined>();
  const [toDate, setToDate] = useState<string | undefined>();
  const [items, setItems] = useState<LedgerEntryDto[]>([]);
  const [loading, setLoading] = useState(false);
  const accountSearchConfig = useMemo(() => createAccountSearchConfig(), []);

  const handleLoad = useCallback(() => {
    if (!accountCode) return;
    setLoading(true);
    ktService.getLedger({ accountCode, fromDate, toDate })
      .then(setItems)
      .catch(err => dispatch(addToast({ message: getApiErrorMessage(err, 'Lỗi tải sổ cái'), type: 'error' })))
      .finally(() => setLoading(false));
  }, [accountCode, fromDate, toDate, dispatch]);

  return (
    <div className={erp.page}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-book-open" /> Sổ cái</h1></div>
      </div>
      <div className={erp.filtersBar} data-testid={`erp-so-cai-filters`}>
        <SearchInput config={accountSearchConfig} value={accountCode} primaryDisplay={accountCode} secondaryDisplay={accountName}
          onChange={a => { setAccountCode(a.code); setAccountName(a.name); }} onClear={() => { setAccountCode(''); setAccountName(''); }}
          showLabel={false} placeholder="Chọn TK" />
        <DateRangeFilter fromDate={fromDate} toDate={toDate} onChange={(v: DateRangeValue) => { setFromDate(v.fromDate); setToDate(v.toDate); }} />
        <Button variant="primary" onClick={handleLoad} loading={loading}>Xem</Button>
        <ListSearchRefreshButtons testIdPrefix="erp-so-cai" onSearch={handleLoad} onRefresh={handleLoad} showSearch={false} />
      </div>
      <div className={erp.tableCard}>
        {items.length === 0 ? <div className={erp.empty}>Chọn tài khoản và bấm Xem</div> : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead><tr><th>Ngày</th><th>Số CT</th><th>Diễn giải</th><th className={erp.colRight}>PS Nợ</th><th className={erp.colRight}>PS Có</th><th className={erp.colRight}>Số dư</th></tr></thead>
              <tbody>{items.map((r, i) => (
                <tr key={i}>
                  <td>{formatDateLocal(r.entryDate)}</td>
                  <td><code>{r.voucherCode}</code></td>
                  <td>{r.description}</td>
                  <td className={erp.colRight}>{formatVnd(r.debitAmount)}</td>
                  <td className={erp.colRight}>{formatVnd(r.creditAmount)}</td>
                  <td className={erp.colRight}>{formatVnd(r.runningBalance)}</td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default SoCaiPage;
